const now = new Date();
const threshold = new Date(now);
threshold.setDate(threshold.getDate() + 2);

return [{
  json: {
    today: now.toISOString(),
    threshold: threshold.toISOString()
  }
}];

parameters.jsonBody:
={
  "query": "query PullsDueSoon($today: DateTime!, $threshold: DateTime!) { pulls(filter: { stage: { eq: OUT }, returnDate: { gte: $today, lte: $threshold } }) { edges { node { id name returnDate client { name { firstName lastName } emails { primaryEmail } } repAssigned { emails { primaryEmail } } } } } }",
  "variables": { "today": "{{ $json.today }}", "threshold": "{{ $json.threshold }}" }
}

